func:
try {
    if (!msg.payload || msg.payload.event !== 'heartbeat') return null;
    if (context.timeout) { clearTimeout(context.timeout); }
    node.status({fill:'green', shape:'dot', text:'Connected'});
    node.send({payload: 'Connected'});
    context.timeout = setTimeout(function() {
        node.status({fill:'red', shape:'ring', text:'Disconnected'});
        node.send({payload: 'Disconnected'});
    }, 90000);
    return null;
} catch(e) {
    node.error('Detect Heartbeat: ' + e.message, msg);
    return null;
}

try {
    var Q = 0.1;
    var R = 2.0;
    var mac = msg.topic;
    if (!mac) return msg;
    var raw = msg.payload;
    var statesKey = env.get('STATES_KEY') || 'kalman_states';
    var states = flow.get(statesKey) || {};
    var s = states[mac] || { x: raw, p: 1.0 };
    var xPred = s.x;
    var pPred = s.p + Q;
    var K = pPred / (pPred + R);
    var xNew = xPred + K * (raw - xPred);
    var pNew = (1 - K) * pPred;
    states[mac] = { x: xNew, p: pNew };
    flow.set(statesKey, states);
    msg.payload = Math.round(xNew * 10) / 10;
    if (msg._label) msg.topic = msg._label;
    return msg;
} catch(e) {
    node.error('Kalman Filter: ' + e.message, msg);
    return null;
}

try {
    var event = msg.payload && msg.payload.event;
    if (event !== 'heartbeat' && event !== 'boot') return null;
    var uuid = msg.topic.split('/')[6];
    if (!uuid) return null;
    var known = flow.get('logKnownUuids') || [];
    if (known.indexOf(uuid) === -1) {
        known.push(uuid);
        known.sort();
        flow.set('logKnownUuids', known);
    }
    msg.payload = known.join(String.fromCharCode(10));
    return msg;
} catch(e) {
    node.error('UUID Logger: ' + e.message, msg);
    return null;
}

try {
    var macs = Array.isArray(msg.payload) ? msg.payload : [msg.payload];
    msg.payload = JSON.stringify({ macs: macs });
    return msg;
} catch(e) {
    node.error('Build track cmd: ' + e.message, msg);
    return null;
}

try {
    var d = msg.payload;
    return [
        { payload: d },
        { payload: parseFloat(d.dist_m) || 0,
          topic:  d.mac || "unknown",
          _label: (d.name ? d.name + " \u00b7 " : "") + (d.mac || "unknown") },
        null
    ];
} catch(e) {
    node.error('Split fields: ' + e.message, msg);
    return null;
}

try {
    const NL = String.fromCharCode(10);
    const beacons = (msg.payload && msg.payload.beacons) || msg.payload;
    if (!Array.isArray(beacons)) { node.error('Expected beacons array', msg); return null; }
    const ts = new Date().toISOString();
    const lines = [];
    if (!flow.get('csvHeaderWritten')) {
        flow.set('csvHeaderWritten', true);
        lines.push('timestamp,mac,name,rssi,dist_m,company_id');
    }
    beacons.forEach(function(b) {
        lines.push([ts, b.mac, b.name || '', b.rssi, b.dist_m, b.company_id].join(','));
    });
    msg.payload = lines.join(NL) + NL;
    return msg;
} catch(e) {
    node.error('Format as CSV: ' + e.message, msg);
    return null;
}

try {
    var d = msg.payload;
    if (!d || !d.mac) return null;
    var devices = flow.get("tracked_devices") || {};
    devices[d.mac] = { mac: d.mac, name: d.name || "", rssi: d.rssi, dist_m: d.dist_m };
    flow.set("tracked_devices", devices);
    msg.payload = { tracking: true, devices: Object.values(devices) };
    return msg;
} catch(e) {
    node.error('Accumulate Tracked Devices: ' + e.message, msg);
    return null;
}

try {
    flow.set("tracked_devices", {});
    node.send([{ payload: { tracking: false, devices: [] } }, { payload: "" }]);
    return null;
} catch(e) {
    node.error('Clear Tracked Context: ' + e.message, msg);
    return null;
}

try {
    flow.set("kalman_states", {});
    msg.payload = [];
    msg.action = "replace";
    return msg;
} catch(e) {
    node.error('Reset Chart Action: ' + e.message, msg);
    return null;
}

try {
    var peers = (msg.payload && Array.isArray(msg.payload.peers))
                ? msg.payload.peers : [];
    var src = msg.payload && msg.payload.node_name ? msg.payload.node_name : null;
    var disc  = flow.get('espnow_discovered') || {};
    var roster = flow.get('espnow_roster') || {};
    peers.forEach(function(p) {
        if (!p.mac) return;
        var name = (roster[p.mac] && roster[p.mac].name) ? roster[p.mac].name : '';
        disc[p.mac] = {
            mac:      p.mac,
            name:     name,
            rssi:     p.rssi,
            rssi_ema: p.rssi_ema,
            dist_m:   p.dist_m,
            rejects:  p.rejects || 0
        };
    });
    flow.set('espnow_discovered', disc);
    msg.payload = { peers: Object.values(disc) };
    return msg;
} catch(e) {
    node.error('Accumulate Discovered: ' + e.message, msg);
    return null;
}

try {
    var disc = flow.get('espnow_discovered') || {};
    msg.payload = { peers: Object.values(disc) };
    return msg;
} catch(e) {
    node.error('Refresh Discovered: ' + e.message, msg);
    return null;
}

try {
    var macs = [].concat(msg.payload || []).filter(function(m) {
        return typeof m === 'string' && m.length > 0;
    });
    flow.set('espnow_tracked_macs', macs);
    var disc = flow.get('espnow_discovered') || {};
    var devices = macs.map(function(mac) { return disc[mac]; }).filter(Boolean);
    var seedMsg = macs.length > 0 ? { payload: { peers: devices } } : null;
    // output 3: publish cmd/espnow/track to firmware (retained)
    var trackMsg = {
        topic: msg._baseTopic ? msg._baseTopic + '/cmd/espnow/track' : null,
        payload: JSON.stringify({ macs: macs }),
        retain: true
    };
    node.send([
        { payload: { tracking: macs.length > 0, devices: devices } },
        seedMsg,
        macs !== undefined ? trackMsg : null
    ]);
    return null;
} catch(e) {
    node.error('Set Tracked MACs: ' + e.message, msg);
    return null;
}

try {
    var tracked = flow.get('espnow_tracked_macs') || [];
    if (tracked.length === 0) return null;
    var peers = (msg.payload && Array.isArray(msg.payload.peers))
                ? msg.payload.peers : [];
    var msgs = [];
    peers.forEach(function(p) {
        if (tracked.indexOf(p.mac) >= 0) {
            var label = p.name || p.mac;
            msgs.push({ payload: parseFloat(p.dist_m) || 0, topic: label, _label: label });
        }
    });
    return msgs.length > 0 ? [msgs] : null;
} catch(e) {
    node.error('Filter Tracked Peers: ' + e.message, msg);
    return null;
}

try {
    flow.set("espnow_tracked_macs", []);
    node.send([
        { payload: { tracking: false, devices: [] } },
        { payload: [], action: "replace" }
    ]);
    return null;
} catch(e) {
    node.error('Stop Tracking: ' + e.message, msg);
    return null;
}

try {
    flow.set('espnow_kalman_states', {});
    msg.payload = [];
    msg.action = 'replace';
    return msg;
} catch(e) {
    node.error('Reset Chart Action: ' + e.message, msg);
    return null;
}

try {
    var base  = global.get('topic_base') || 'Enigma/JHBDev/Office/Line/Cell/ESP32NodeBox/';
    var devs  = global.get('hb_devices') || {};
    var uuids = Object.keys(devs);
    if (uuids.length === 0) {
        node.warn('ESP-NOW ranging cmd: no known devices yet');
        return null;
    }
    var enable = (msg.payload && msg.payload.tracking) ? '1' : '0';
    uuids.forEach(function(uuid) {
        node.send({
            topic:  base + uuid + '/cmd/espnow/ranging',
            payload: enable,
            retain:  true,
            qos:     1
        });
    });
    return null;
} catch(e) {
    node.error('ESP-NOW ranging cmd: ' + e.message, msg);
    return null;
}

try {
    var tags = {};
    if (msg.payload && typeof msg.payload === 'string' && msg.payload.trim().length) {
        try { tags = JSON.parse(msg.payload) || {}; }
        catch(e) { node.warn('rfid_tags.json parse: ' + e.message); tags = {}; }
    }
    global.set('rfid_tags', tags);
    return null;
} catch(e) { node.error('rfid_init_fn: ' + e.message, msg); return null; }

try {
    var uuid = msg.topic.split('/')[6] || '';
    var p = msg.payload || {};
    var uid = p.uid || '';
    if (!uid) return null;
    var feed = flow.get('rfid_feed') || [];
    var devices = global.get('hb_devices') || {};
    var reader = (devices[uuid] && devices[uuid].name) || (uuid.slice(0,8) + '...');
    feed.unshift({
        ts: new Date().toLocaleString(),
        uid: uid,
        profile: p.profile || 'unknown',
        card_type: p.card_type || '',
        authorized: p.authorized === true,
        reader: reader,
        reader_uuid: uuid
    });
    if (feed.length > 50) feed.length = 50;
    flow.set('rfid_feed', feed);
    // upsert registry
    var tags = global.get('rfid_tags') || {};
    var now = new Date().toISOString();
    var prev = tags[uid] || { first_seen: now, label: '', notes: '' };
    tags[uid] = {
        label:      prev.label || '',
        notes:      prev.notes || '',
        profile:    p.profile || prev.profile || 'unknown',
        first_seen: prev.first_seen || now,
        last_seen:  now,
        last_reader: reader
    };
    global.set('rfid_tags', tags);
    node.send([{ payload: feed }, { payload: tags }]);
    return null;
} catch(e) { node.error('rfid_scan_fn: ' + e.message, msg); return null; }

try {
    if (!msg || msg.topic !== 'edit' || !msg.payload || !msg.payload.uid) return null;
    var tags = global.get('rfid_tags') || {};
    var t = tags[msg.payload.uid];
    if (!t) return null;
    if (msg.payload.field === 'label') t.label = String(msg.payload.value || '');
    if (msg.payload.field === 'notes') t.notes = String(msg.payload.value || '');
    tags[msg.payload.uid] = t;
    global.set('rfid_tags', tags);
    return { payload: tags };
} catch(e) { node.error('rfid_assign_edit_fn: ' + e.message, msg); return null; }

try {
    var d = global.get('hb_devices') || {};
    var readers = Object.keys(d)
        .filter(function(u){ return d[u] && d[u].status === 'Connected'; })
        .map(function(u){ return { uuid: u, name: d[u].name || u.slice(0,8) + '...' }; });
    readers.sort(function(a,b){ return a.name.localeCompare(b.name); });
    return { topic: 'readers', payload: readers };
} catch(e) { node.error('rfid_readers_fn: ' + e.message, msg); return null; }

try {
    var p = msg.payload || {};
    var uuid = p.reader_uuid;
    if (!uuid) return null;
    var base = (global.get('topic_base') || 'Enigma/JHBDev/Office/Line/Cell/ESP32NodeBox/') + uuid + '/';
    if (msg.topic === 'write') {
        return { topic: base + 'cmd/rfid/program', payload: {
            profile: p.profile,
            writes: [{ block: p.block, data_hex: String(p.data_hex||'').toUpperCase(),
                       key_a_hex: String(p.key_a_hex||'FFFFFFFFFFFF').toUpperCase() }],
            timeout_ms: 15000,
            request_id: p.request_id
        }};
    }
    if (msg.topic === 'read') {
        return { topic: base + 'cmd/rfid/read_block', payload: {
            profile: p.profile, block: p.block,
            key_a_hex: String(p.key_a_hex||'FFFFFFFFFFFF').toUpperCase(),
            timeout_ms: 15000,
            request_id: p.request_id
        }};
    }
    if (msg.topic === 'cancel') {
        return { topic: base + 'cmd/rfid/cancel', payload: {} };
    }
    return null;
} catch(e) { node.error('rfid_program_encode_fn: ' + e.message, msg); return null; }

try {
    var p = msg.payload || {};
    if (p.event !== 'rfid_program' && p.event !== 'rfid_read_block') return null;
    return { topic: 'response', payload: p };
} catch(e) { node.error('rfid_response_fn: ' + e.message, msg); return null; }

try {
    var d = global.get('hb_devices') || {};
    var list = Object.keys(d).map(function(u){ return { uuid: u, name: (d[u] && d[u].name) || u.slice(0,8) + '...' }; });
    list.sort(function(a,b){ return a.name.localeCompare(b.name); });
    return { topic: 'devices', payload: list };
} catch(e) { node.error('led_dev_list_fn: ' + e.message, msg); return null; }

try {
    if (msg && msg.topic === 'select' && msg.payload && msg.payload.uuid) {
        flow.set('led_selected_uuid', msg.payload.uuid);
    }
    return null;
} catch(e) { node.error('led_selection_fn: ' + e.message, msg); return null; }

try {
    var uuid = flow.get('led_selected_uuid');
    if (!uuid) { node.warn('No device selected'); return null; }
    var base = flow.get('topic_base') || global.get('topic_base') || 'Enigma/JHBDev/Office/Line/Cell/ESP32NodeBox/';
    var t = base + uuid + '/cmd/led';
    var body = null;
    switch (msg.topic) {
      case 'color':
        if (!msg.payload) return null;
        body = { cmd:'color', r: msg.payload.r|0, g: msg.payload.g|0, b: msg.payload.b|0 };
        break;
      case 'brightness':
        body = { cmd:'brightness', value: (msg.payload && msg.payload.value)|0 };
        break;
      case 'count':
        body = { cmd:'count', value: (msg.payload && msg.payload.value)|0 };
        break;
      case 'animation':
        body = { cmd:'animation', name: (msg.payload && msg.payload.name) || 'solid' };
        break;
      case 'off':   body = { cmd:'off' };   break;
      case 'reset': body = { cmd:'reset' }; break;
      default: return null;
    }
    return { topic: t, payload: body };
} catch(e) { node.error('led_encode_fn: ' + e.message, msg); return null; }

try {
    var uuid = msg.topic.split('/')[6] || '';
    if (!uuid || !msg.payload) return null;
    var all = flow.get('led_state') || {};
    var devices = global.get('hb_devices') || {};
    var name = (devices[uuid] && devices[uuid].name) || (uuid.slice(0,8) + '...');
    all[uuid] = {
        uuid:       uuid,
        name:       name,
        state:      msg.payload.state || '—',
        r:          msg.payload.r|0,
        g:          msg.payload.g|0,
        b:          msg.payload.b|0,
        brightness: msg.payload.brightness|0,
        count:      msg.payload.count|0,
        uptime_s:   msg.payload.uptime_s|0,
        ts:         new Date().toLocaleString()
    };
    flow.set('led_state', all);
    var rows = Object.values(all).sort(function(a,b){ return a.name.localeCompare(b.name); });
    return { payload: rows };
} catch(e) { node.error('led_state_fn: ' + e.message, msg); return null; }

try {
    if (!msg || msg.topic !== 'locate' || !msg.payload || !msg.payload.uuid) return null;
    var base = flow.get('topic_base') || global.get('topic_base') || 'Enigma/JHBDev/Office/Line/Cell/ESP32NodeBox/';
    return { topic: base + msg.payload.uuid + '/cmd/locate', payload: '' };
} catch(e) { node.error('led_locate_fn: ' + e.message, msg); return null; }

try {
    var p = msg.payload || {};
    var uid = p.uid || '';
    if (!uid) return null;
    var uuid = msg.topic.split('/')[6] || '';
    var devices = global.get('hb_devices') || {};
    var reader = (devices[uuid] && devices[uuid].name) || uuid.slice(0,8);
    var ts = new Date().toISOString();
    var lines = [];
    if (flow.get('rfid_csv_header_written') !== true) {
        lines.push('timestamp,uid,profile,card_type,authorized,reader,reader_uuid');
        flow.set('rfid_csv_header_written', true);
    }
    lines.push([
        ts, uid,
        String(p.profile || '').replace(/,/g, ';'),
        String(p.card_type || '').replace(/,/g, ';'),
        p.authorized === true ? 'true' : 'false',
        reader.replace(/,/g, ';'),
        uuid
    ].join(','));
    msg.payload = lines.join('\n') + '\n';
    return msg;
} catch(e) { node.error('rfid_csv_fn: ' + e.message, msg); return null; }

// Only forward messages that are user tracking selections (Array of MAC strings).
// Drop display messages like { peers:[...] } that come from refresh/discover.
try {
    if (Array.isArray(msg.payload)) return msg;
    return null;
} catch(e) {
    node.error('espnow_track_guard_fn: ' + e.message, msg);
    return null;
}

try {
    var event = msg.payload && msg.payload.event;
    if (event !== 'heartbeat' && event !== 'boot' &&
        event !== 'ota_start'  && event !== 'restart' &&
        event !== 'sleeping'   && event !== 'deep_sleeping' && event !== 'modem_sleeping' &&
        event !== 'locating') return null;
    var uuid    = msg.topic.split('/')[6];
    if (!uuid) return null;
    var fw      = (msg.payload && msg.payload.firmware_version) || '';
    var uptime  = (msg.payload && msg.payload.uptime_s)         || 0;
    var rfid_en = (msg.payload && msg.payload.rfid_enabled)     === true;

    if (event === 'ota_start') {
        node.status({ fill:'yellow', shape:'dot', text: uuid + ' updating' });
        msg.uuid=uuid; msg.firmware_version=fw; msg.uptime_s=uptime;
        msg.rfid_enabled=rfid_en; msg.payload='Updating';
        return msg;
    }
    if (event === 'restart') {
        node.status({ fill:'orange', shape:'dot', text: uuid + ' restarting' });
        msg.uuid=uuid; msg.firmware_version=fw; msg.uptime_s=uptime;
        msg.rfid_enabled=rfid_en; msg.payload='Restarting';
        return msg;
    }
    if (event === 'sleeping' || event === 'deep_sleeping' || event === 'modem_sleeping') {
        var durationS = Number((msg.payload && msg.payload.duration_s) || 0);
        var label = event === 'sleeping'      ? 'Sleeping'
                  : event === 'deep_sleeping' ? 'Deep Sleeping'
                  :                             'Modem Sleeping';
        node.status({ fill:'blue', shape:'dot', text: uuid + ' ' + label.toLowerCase() });
        var timeouts = context.get('timeouts') || {};
        if (timeouts[uuid]) clearTimeout(timeouts[uuid]);
        if (event !== 'modem_sleeping') {
            var graceMs = (event === 'deep_sleeping' ? 60 : 30) * 1000;
            timeouts[uuid] = setTimeout(function () {
                node.status({ fill:'red', shape:'ring', text: uuid + ' disconnected' });
                node.send({ payload:'Disconnected', uuid:uuid,
                            firmware_version:'', uptime_s:0, rfid_enabled:false });
            }, durationS * 1000 + graceMs);
            context.set('timeouts', timeouts);
        }
        msg.uuid=uuid; msg.firmware_version=fw; msg.uptime_s=uptime; msg.rfid_enabled=rfid_en;
        msg.payload = label;
        msg._sleep_duration_s = durationS;
        msg._wake_at_ms = Date.now() + durationS * 1000;
        return msg;
    }
    if (event === 'locating') {
        var hbDevs = flow.get('hb_devices') || {};
        var stored = hbDevs[uuid];
        msg.uuid = uuid; msg.firmware_version = fw; msg.uptime_s = uptime; msg.rfid_enabled = rfid_en;
        msg.payload = (stored && stored.status) || 'Connected';
        msg._locating_until_ms = Date.now() + 4100;
        return msg;
    }
    // heartbeat / boot
    var timeouts = context.get('timeouts') || {};
    if (timeouts[uuid]) clearTimeout(timeouts[uuid]);
    var hbDevs2 = flow.get('hb_devices') || {};
    var storedDev = hbDevs2[uuid] || {};
    if (storedDev.status === 'Modem Sleeping' && storedDev.wake_at_ms && storedDev.wake_at_ms > Date.now()) {
        msg.uuid=uuid; msg.firmware_version=fw; msg.uptime_s=uptime; msg.rfid_enabled=rfid_en;
        msg.payload = 'Modem Sleeping';
        msg._wake_at_ms = storedDev.wake_at_ms;
        msg._sleep_duration_s = storedDev.sleep_duration_s;
        return msg;
    }
    node.status({ fill:'green', shape:'dot', text: uuid + ' connected' });
    timeouts[uuid] = setTimeout(function () {
        node.status({ fill:'red', shape:'ring', text: uuid + ' disconnected' });
        node.send({ payload:'Disconnected', uuid:uuid,
                    firmware_version:'', uptime_s:0, rfid_enabled:false });
    }, 90000);
    context.set('timeouts', timeouts);
    msg.uuid=uuid; msg.firmware_version=fw; msg.uptime_s=uptime;
    msg.rfid_enabled=rfid_en; msg.payload='Connected';
    return msg;
} catch(e) {
    node.error('Detect Heartbeat: ' + e.message, msg);
    return null;
}

try {
    if (!msg.payload || msg.payload.event !== 'heartbeat') return null;
    if (context.timeout) { clearTimeout(context.timeout); }
    node.status({fill:'green', shape:'dot', text:'Connected'});
    node.send([{payload: 'Connected'}, null]);
    context.timeout = setTimeout(function() {
        node.status({fill:'red', shape:'ring', text:'Disconnected'});
        node.send([null, {payload: 'Disconnected'}]);
    }, 90000);
    return null;
} catch(e) {
    node.error('Detect Heartbeat: ' + e.message, msg);
    return null;
}

try {
    msg.payload = "Device 'ESP32 - Alpha' (Office/Line/Cell NodeBox, ID: 32925666-155a-4a67-bf50-27c1ffa22b11) has gone offline. No heartbeat received for over 90 seconds.";
    msg.systemPrompt = "You are an IoT monitoring assistant. When a device goes offline, respond with a 2-3 sentence alert summary and one actionable next step for the engineer. Be concise.";
    return msg;
} catch(e) {
    node.error('Prepare Claude Alert: ' + e.message, msg);
    return null;
}

try {
    const names = {
      '32925666-155a-4a67-bf50-27c1ffa22b11': 'ESP32-Alpha',
      '6cfe177f-92eb-4699-a9a6-8a3603aae175': 'ESP32-Bravo',
      '79eb6f5f-2072-4904-b91d-50601f195c18': 'ESP32-Charlie'
    };
    const uuid = msg.uuid;
    if (!uuid) return null;
    const devices = flow.get('hb_devices') || {};
    const prev    = devices[uuid] || {};
    const active  = msg.payload === 'Connected' || msg.payload === 'Updating' || msg.payload === 'Restarting';
    const isSleep = msg.payload === 'Sleeping' || msg.payload === 'Deep Sleeping' || msg.payload === 'Modem Sleeping';
    const clearSleep = (msg.payload === 'Connected') && (msg._wake_at_ms === undefined);
    const wakeAt   = (msg._wake_at_ms !== undefined) ? msg._wake_at_ms : clearSleep ? undefined : prev.wake_at_ms;
    const sleepDur = (msg._sleep_duration_s !== undefined) ? msg._sleep_duration_s : clearSleep ? undefined : prev.sleep_duration_s;
    const locatingUntil = (msg._locating_until_ms !== undefined) ? msg._locating_until_ms : (prev.locating_until_ms || 0);
    devices[uuid] = {
      name:              names[uuid] || uuid.slice(0,8) + '...',
      uuid:              uuid,
      status:            msg.payload,
      firmware:          (active || isSleep) && msg.firmware_version ? msg.firmware_version : (prev.firmware || '—'),
      lastSeen:          (active || isSleep) ? new Date().toLocaleString() : (prev.lastSeen || 'Never'),
      rfid_enabled:      (msg.payload === 'Connected') ? (msg.rfid_enabled === true) : (prev.rfid_enabled === true),
      wake_at_ms:        wakeAt,
      sleep_duration_s:  sleepDur,
      locating_until_ms: locatingUntil
    };
    flow.set('hb_devices', devices);
    global.set('hb_devices', devices);
    msg.payload = Object.values(devices).sort((a,b) => a.name.localeCompare(b.name));
    return msg;
} catch(e) {
    node.error('Aggregate Device Status: ' + e.message, msg);
    return null;
}

try {
    var base = flow.get("topic_base") || "Enigma/JHBDev/Office/Line/Cell/ESP32NodeBox/";
    var uuids = Object.keys(flow.get("hb_devices") || {});
    if (uuids.length === 0) {
        node.warn("No known devices yet — waiting for first heartbeat");
        return null;
    }
    uuids.forEach(function(uuid) {
        node.send({
            topic: base + uuid + "/cmd/ota_check",
            payload: ""
        });
    });
    return null;
} catch(e) {
    node.error("Publish to All Devices: " + e.message, msg);
    return null;
}

try {
    var base    = flow.get('topic_base') || 'Enigma/JHBDev/Office/Line/Cell/ESP32NodeBox/';
    var devices = flow.get('hb_devices') || {};
    var uuids   = Object.keys(devices);
    if (uuids.length === 0) {
        node.warn('No known devices — waiting for first heartbeat');
        return null;
    }
    uuids.forEach(function(u) {
        if (devices[u] && devices[u].status === 'Connected') {
            devices[u].status = 'Restarting';
        }
    });
    flow.set('hb_devices', devices);
    global.set('hb_devices', devices);
    var sorted = Object.values(devices).sort(function(a,b){ return a.name.localeCompare(b.name); });
    uuids.forEach(function(uuid) {
        node.send([{ topic: base + uuid + '/cmd/restart', payload: '' }, null]);
    });
    node.send([null, { payload: sorted }]);
    return null;
} catch(e) {
    node.error('Restart All Devices: ' + e.message, msg);
    return null;
}

flow.set('topic_base', 'Enigma/JHBDev/Office/Line/Cell/ESP32NodeBox/');
global.set('topic_base', 'Enigma/JHBDev/Office/Line/Cell/ESP32NodeBox/');
return null;

try {
    if (!msg || msg.topic !== 'locate' || !msg.payload || !msg.payload.uuid) return null;
    var base = flow.get('topic_base') || global.get('topic_base') || 'Enigma/JHBDev/Office/Line/Cell/ESP32NodeBox/';
    return { topic: base + msg.payload.uuid + '/cmd/locate', payload: '' };
} catch(e) { node.error('hb_locate_fn: ' + e.message, msg); return null; }

try {
    if (!msg || msg.topic !== 'sleep_cmd' || !msg.payload) return null;
    var base    = flow.get('topic_base') || 'Enigma/JHBDev/Office/Line/Cell/ESP32NodeBox/';
    var devices = flow.get('hb_devices') || {};
    var uuid    = msg.payload.uuid;
    var seconds = msg.payload.seconds;
    var kind    = msg.payload.kind;

    if (!uuid || !devices[uuid]) { node.warn('hb_sleep_fn: unknown uuid'); return null; }
    if (!(seconds >= 1 && seconds <= 86400)) { node.warn('hb_sleep_fn: bad seconds ' + seconds); return null; }
    if (['modem','light','deep'].indexOf(kind) === -1) { node.warn('hb_sleep_fn: bad kind'); return null; }

    var statusLabel = kind === 'deep'  ? 'Deep Sleeping'
                    : kind === 'light' ? 'Sleeping'
                    :                    'Modem Sleeping';
    var topicLeaf   = kind === 'deep'  ? 'deep_sleep'
                    : kind === 'light' ? 'sleep'
                    :                    'modem_sleep';

    devices[uuid].status           = statusLabel;
    devices[uuid].sleep_duration_s = seconds;
    devices[uuid].wake_at_ms       = Date.now() + seconds * 1000;
    flow.set('hb_devices', devices);
    global.set('hb_devices', devices);
    var sorted = Object.values(devices).sort(function(a,b){ return a.name.localeCompare(b.name); });

    node.send([
        { topic: base + uuid + '/cmd/' + topicLeaf,
          payload: JSON.stringify({ seconds: seconds }), qos: 1, retain: false },
        { payload: sorted }
    ]);
    return null;
} catch(e) {
    node.error('hb_sleep_fn: ' + e.message, msg);
    return null;
}

try {
    var p = msg.payload || {};
    if (!p.mac) return null;
    // UUID lives in topic position 6: Enigma/.../ESP32NodeBox/{uuid}/status
    var uuid = (msg.topic || '').split('/')[6] || p.device_id || p.mac;
    // Existing friendly name from the global heartbeat registry (ESP32-Alpha etc.)
    var hbDevices = global.get('hb_devices') || {};
    var hbName = (hbDevices[uuid] && hbDevices[uuid].name) ? hbDevices[uuid].name : '';
    var roster = flow.get('espnow_roster') || {};
    var prev = roster[p.mac] || {};
    // Priority: firmware node_name > roster name persisted from a previous rename cmd > hb_devices name > short uuid
    var name = (p.node_name || '').trim()
             || (prev.name || '').trim()
             || hbName
             || uuid.slice(0, 8) + '...';
    // Collision detection
    Object.keys(roster).forEach(function(mac) {
        if (mac !== p.mac && roster[mac].name === name) { name = name + '#2'; }
    });
    roster[p.mac] = { uuid: uuid, mac: p.mac, name: name, online: p.online !== false };
    flow.set('espnow_roster', roster);
    var disc = flow.get('espnow_discovered') || {};
    if (disc[p.mac]) disc[p.mac].name = name;
    flow.set('espnow_discovered', disc);
    var devices = Object.values(roster).map(function(r) {
        return { uuid: r.uuid, mac: r.mac, name: r.name, online: r.online };
    });
    return { payload: { devices: devices } };
} catch(e) {
    node.error('Build Roster: ' + e.message, msg);
    return null;
}

try {
    var mac  = msg.payload && msg.payload.mac;
    var name = msg.payload && msg.payload.name;
    if (!mac || !name) return null;
    // Derive base topic from retained roster (status topic minus '/status')
    // Fallback: use wildcard-matched topic from espnow_status_in for this mac.
    // We embed the MAC in the payload so Node-RED can route; firmware ignores mac field.
    var topic = 'Enigma/JHBDev/Office/Line/Cell/ESP32NodeBox/' + mac + '/cmd/espnow/name';
    return {
        topic: topic,
        payload: JSON.stringify({ name: name }),
        retain: true,
        qos: 1
    };
} catch(e) {
    node.error('Build Name Cmd: ' + e.message, msg);
    return null;
}

try {
    var p = msg.payload || {};
    var mac = p.mac;
    if (!mac) return null;
    var cmdPayload = { cmd: p.cmd };
    if (p.cmd === 'measure_1m') { cmdPayload.samples = p.samples || 30; }
    if (p.cmd === 'measure_d')  { cmdPayload.samples = p.samples || 30; cmdPayload.distance_m = p.distance_m; }
    var topic = 'Enigma/JHBDev/Office/Line/Cell/ESP32NodeBox/' + mac + '/cmd/espnow/calibrate';
    return { topic: topic, payload: JSON.stringify(cmdPayload), qos: 1, retain: false };
} catch(e) {
    node.error('Build Calib Cmd: ' + e.message, msg);
    return null;
}

try {
    var alpha   = msg.payload.alpha_x100;
    var outlier = msg.payload.outlier_db;
    var roster  = flow.get('espnow_roster') || {};
    var macs = Object.keys(roster);
    if (macs.length === 0) {
        node.warn('No known devices in roster yet');
        return null;
    }
    var msgs = macs.map(function(mac) {
        return {
            topic: 'Enigma/JHBDev/Office/Line/Cell/ESP32NodeBox/' + mac + '/cmd/espnow/filter',
            payload: JSON.stringify({ alpha_x100: alpha, outlier_db: outlier }),
            retain: true,
            qos: 1
        };
    });
    node.send([msgs]);
    return null;
} catch(e) {
    node.error('Build Filter Cmds: ' + e.message, msg);
    return null;
}
